import logging
import sys

def setup_logging(verbose=False):
    level = logging.DEBUG if verbose else logging.INFO
    logging.basicConfig(
        level=level,
        format='%(asctime)s - %(levelname)s - %(message)s',
        handlers=[logging.StreamHandler(sys.stdout)]
    )
    return logging.getLogger(__name__)

import json
from pathlib import Path

def load_config(config_path='config.json'):
    path = Path(config_path)
    if not path.exists():
        raise FileNotFoundError(f'Config not found: {config_path}')
    with open(path) as f:
        return json.load(f)

def __init__(self, page):
    self.page = page
    self.file_picker = ft.FilePicker(on_result=self._on_file_selected)
    self.page.overlay.append(self.file_picker)

def _build_drop_zone(self):
    return ft.Container(
        content=ft.Column([
            ft.Icon(ft.icons.UPLOAD_FILE, size=48, color='#00d084'),
            ft.Text('Arrastra un archivo o haz clic', size=16, color='#94a3b8'),
            ft.Text('Formatos: .xlsx, .xls, .csv', size=12, color='#64748b'),
        ], horizontal_alignment=ft.CrossAxisAlignment.CENTER),
        bgcolor='#1a2332',
        border=ft.border.all(2, '#00d08440'),
        border_radius=12,
        padding=40,
        on_click=lambda _: self.file_picker.pick_files(allow_multiple=False),
        ink=True,
    )

def _on_file_selected(self, e):
    if e.files:
        file = e.files[0]
        self._process_file(file.path, file.name)

def _build_pagination(self, page, total_pages, on_page_change):
    controls = []
    controls.append(ft.IconButton(ft.icons.CHEVRON_LEFT, on_click=lambda _: on_page_change(page - 1)))
    for p in range(max(0, page - 2), min(total_pages, page + 3)):
        controls.append(
            ft.Container(
                content=ft.Text(str(p + 1), size=14, color='#00d084' if p == page else '#94a3b8'),
                padding=10,
                on_click=lambda _, x=p: on_page_change(x),
            )
        )
    controls.append(ft.IconButton(ft.icons.CHEVRON_RIGHT, on_click=lambda _: on_page_change(page + 1)))
    return ft.Row(controls, alignment=ft.MainAxisAlignment.CENTER)

import traceback
import logging

logger = logging.getLogger('g360-app')

def safe_handler(fn):
    """Decorator que atrapa excepciones en callbacks Flet."""
    def wrapper(*args, **kwargs):
        try:
            return fn(*args, **kwargs)
        except Exception as e:
            logger.error(f'Error en {fn.__name__}: {e}\n{traceback.format_exc()}')
            page = args[0].page if hasattr(args[0], 'page') else None
            if page:
                page.snack_bar = ft.SnackBar(
                    content=ft.Text(f'Error: {str(e)[:80]}'),
                    bgcolor='#ef4444',
                )
                page.snack_bar.open = True
                page.update()
    return wrapper

